update public.source_documents sd
set
  source_uri = drive_links.drive_url,
  storage_path = null,
  metadata_json = sd.metadata_json || jsonb_build_object(
    'external_source_folder_url', 'https://drive.google.com/drive/folders/1hvGKw0bAPbh-RXCJgz_7j4SWUsWhIxo-',
    'google_drive_file_id', drive_links.drive_file_id,
    'google_drive_file_url', drive_links.drive_url,
    'source_uri_replaced_at', timezone('utc', now())
  )
from drive_links
where sd.id = drive_links.source_document_id;
